-- <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#drawing-conditional-rendering conditional rendering>
--
-- = See Also
--
-- <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#VK_EXT_transform_feedback VK_EXT_transform_feedback>,
-- <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#VK_KHR_device_address_commands VK_KHR_device_address_commands>,
-- 'BindTransformFeedbackBuffer2InfoEXT',
-- 'Vulkan.Core10.Handles.CommandBuffer'
cmdEndTransformFeedback2EXT :: forall io
                             . (MonadIO io)
                            => -- | @commandBuffer@ is the command buffer into which the command is
                               -- recorded.
                               CommandBuffer
                            -> -- No documentation found for Nested "vkCmdEndTransformFeedback2EXT" "firstCounterRange"
                               ("firstCounterRange" ::: Word32)
                            -> -- | @counterRangeCount@ is the size of the @pCounterInfos@ array.
                               ("counterRangeCount" ::: Word32)
                            -> -- | @pCounterInfos@ is @NULL@ or a pointer to an array of
                               -- 'BindTransformFeedbackBuffer2InfoEXT' structures defining memory ranges
                               -- used to write counters used to later resume transform feedback.
                               ("counterInfos" ::: Vector BindTransformFeedbackBuffer2InfoEXT)
                            -> io ()
cmdEndTransformFeedback2EXT commandBuffer
                              firstCounterRange
                              counterRangeCount
                              counterInfos = liftIO . evalContT $ do
  let vkCmdEndTransformFeedback2EXTPtr = pVkCmdEndTransformFeedback2EXT (case commandBuffer of CommandBuffer{deviceCmds} -> deviceCmds)
  lift $ unless (vkCmdEndTransformFeedback2EXTPtr /= nullFunPtr) $
    throwIO $ IOError Nothing InvalidArgument "" "The function pointer for vkCmdEndTransformFeedback2EXT is null" Nothing Nothing
  let vkCmdEndTransformFeedback2EXT' = mkVkCmdEndTransformFeedback2EXT vkCmdEndTransformFeedback2EXTPtr
  let pCounterInfosLength = Data.Vector.length $ (counterInfos)
  counterRangeCount' <- lift $ if (counterRangeCount) == 0
    then pure $ fromIntegral pCounterInfosLength
    else do
      unless (fromIntegral pCounterInfosLength == (counterRangeCount) || pCounterInfosLength == 0) $
        throwIO $ IOError Nothing InvalidArgument "" "pCounterInfos must be empty or have 'counterRangeCount' elements" Nothing Nothing
      pure (counterRangeCount)
  pCounterInfos <- if Data.Vector.null (counterInfos)
    then pure nullPtr
    else do
      pPCounterInfos <- ContT $ allocaBytes @BindTransformFeedbackBuffer2InfoEXT (((Data.Vector.length (counterInfos))) * 40)
      lift $ Data.Vector.imapM_ (\i e -> poke (pPCounterInfos `plusPtr` (40 * (i)) :: Ptr BindTransformFeedbackBuffer2InfoEXT) (e)) ((counterInfos))
      pure $ pPCounterInfos
  lift $ traceAroundEvent "vkCmdEndTransformFeedback2EXT" (vkCmdEndTransformFeedback2EXT'
                                                             (commandBufferHandle (commandBuffer))
                                                             (firstCounterRange)
                                                             (counterRangeCount')
                                                             pCounterInfos)
  pure $ ()


