-- @pInfos@ replace the current state for the vertex input binding
-- @firstBinding@ + i, for i in [0, @bindingCount@). The vertex input
-- binding is updated to the range of memory indicated by @pInfos@[i]. All
-- vertex input attributes that use each of these bindings will use these
-- updated addresses in their address calculations for subsequent drawing
-- commands. If the
-- <https://registry.khronos.org/vulkan/specs/latest/html/vkspec.html#features-nullDescriptor nullDescriptor>
-- feature is enabled, elements of @pInfos@ /can/ have a
-- @addressRange.size@ and @addressRange.address@ of 0. If a vertex input
-- attribute is bound to a vertex input binding with a @size@ and @address@
-- of 0, the values taken from memory are considered to be zero, and
-- missing G, B, or A components are
-- <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#fxvertex-input-extraction filled with (0,0,1)>.
--
-- This command also
-- <https://registry.khronos.org/vulkan/specs/latest/html/vkspec.html#pipelines-dynamic-state dynamically sets>
-- the byte strides between consecutive elements within the strided range
-- defined by @pInfos@[i] to the value of @pInfos@[i].addressRange.stride
-- when drawing using
-- <https://registry.khronos.org/vulkan/specs/latest/html/vkspec.html#shaders-objects shader objects>,
-- or when the graphics pipeline is created with
-- 'Vulkan.Core10.Enums.DynamicState.DYNAMIC_STATE_VERTEX_INPUT_BINDING_STRIDE'
-- set in
-- 'Vulkan.Core10.GraphicsPipeline.PipelineDynamicStateCreateInfo'::@pDynamicStates@.
-- Otherwise, strides are specified by the
-- VkVertexInputBindingDescription::stride values used to create the
-- currently active pipeline.
--
-- If drawing using
-- <https://registry.khronos.org/vulkan/specs/latest/html/vkspec.html#shaders-objects shader objects>
-- or if the bound pipeline state object was also created with the
-- 'Vulkan.Core10.Enums.DynamicState.DYNAMIC_STATE_VERTEX_INPUT_EXT'
-- dynamic state enabled then
-- 'Vulkan.Extensions.VK_EXT_vertex_input_dynamic_state.cmdSetVertexInputEXT'
-- /can/ be used instead of
-- 'Vulkan.Core13.Promoted_From_VK_EXT_extended_dynamic_state.cmdBindVertexBuffers2'
-- to set the stride.
--
-- Unlike the static state to set the same, @stride@ for each address range
-- must be between 0 and the maximum extent of the attributes in the
-- binding.
-- 'Vulkan.Extensions.VK_EXT_vertex_input_dynamic_state.cmdSetVertexInputEXT'
-- does not have this restriction so can be used if other stride values are
-- desired.
--
-- == Valid Usage
--
-- -   #VUID-vkCmdBindVertexBuffers3KHR-firstBinding-13070# @firstBinding@
--     /must/ be less than
--     'Vulkan.Core10.DeviceInitialization.PhysicalDeviceLimits'::@maxVertexInputBindings@
--
-- -   #VUID-vkCmdBindVertexBuffers3KHR-firstBinding-13071# The sum of
--     @firstBinding@ and @bindingCount@ /must/ be less than or equal to
--     'Vulkan.Core10.DeviceInitialization.PhysicalDeviceLimits'::@maxVertexInputBindings@
--
-- -   #VUID-vkCmdBindVertexBuffers3KHR-addressRange-13073# The
--     @addressRange.stride@ of all elements of @pInfos@ /must/ be either 0
--     or greater than or equal to the maximum extent of all vertex input
--     attributes fetched from the corresponding binding, where the extent
--     is calculated as the
--     'Vulkan.Core10.GraphicsPipeline.VertexInputAttributeDescription'::@offset@
--     plus
--     'Vulkan.Core10.GraphicsPipeline.VertexInputAttributeDescription'::@format@
--     size
--
-- == Valid Usage (Implicit)
--
-- -   #VUID-vkCmdBindVertexBuffers3KHR-commandBuffer-parameter#
--     @commandBuffer@ /must/ be a valid
--     'Vulkan.Core10.Handles.CommandBuffer' handle
--
-- -   #VUID-vkCmdBindVertexBuffers3KHR-pBindingInfos-parameter#
--     @pBindingInfos@ /must/ be a valid pointer to an array of
--     @bindingCount@ valid 'BindVertexBuffer3InfoKHR' structures
--
-- -   #VUID-vkCmdBindVertexBuffers3KHR-commandBuffer-recording#
--     @commandBuffer@ /must/ be in the
--     <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#commandbuffers-lifecycle recording state>
--
-- -   #VUID-vkCmdBindVertexBuffers3KHR-commandBuffer-cmdpool# The
--     'Vulkan.Core10.Handles.CommandPool' that @commandBuffer@ was
--     allocated from /must/ support
--     'Vulkan.Core10.Enums.QueueFlagBits.QUEUE_GRAPHICS_BIT' operations
--
-- -   #VUID-vkCmdBindVertexBuffers3KHR-videocoding# This command /must/
--     only be called outside of a video coding scope
--
-- -   #VUID-vkCmdBindVertexBuffers3KHR-bindingCount-arraylength#
--     @bindingCount@ /must/ be greater than @0@
--
-- == Host Synchronization
--
-- -   Host access to @commandBuffer@ /must/ be externally synchronized
--
-- -   Host access to the 'Vulkan.Core10.Handles.CommandPool' that
--     @commandBuffer@ was allocated from /must/ be externally synchronized
--
-- == Command Properties
--
-- \'
--
-- +----------------------------------------------------------------------------------------------------------------------------+------------------------------------------------------------------------------------------------------------------------+-----------------------------------------------------------------------------------------------------------------------------+-----------------------------------------------------------------------------------------------------------------------+----------------------------------------------------------------------------------------------------------------------------------------+
-- | <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#VkCommandBufferLevel Command Buffer Levels> | <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#vkCmdBeginRenderPass Render Pass Scope> | <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#vkCmdBeginVideoCodingKHR Video Coding Scope> | <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#VkQueueFlagBits Supported Queue Types> | <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#fundamentals-queueoperation-command-types Command Type> |
-- 
-- | Primary                                                                                                                    | Both                                                                                                                   | Outside                                                                                                                     | VK_QUEUE_GRAPHICS_BIT                                                                                                 | State                                                                                                                                  |
-- | Secondary                                                                                                                  |                                                                                                                        |                                                                                                                             |                                                                                                                       |                                                                                                                                        |
-- +----------------------------------------------------------------------------------------------------------------------------+------------------------------------------------------------------------------------------------------------------------+-----------------------------------------------------------------------------------------------------------------------------+-----------------------------------------------------------------------------------------------------------------------+----------------------------------------------------------------------------------------------------------------------------------------+
--
-- == Conditional Rendering
--
-- vkCmdBindVertexBuffers3KHR is not affected by
-- <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#drawing-conditional-rendering conditional rendering>
--
-- = See Also
--
-- <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#VK_KHR_device_address_commands VK_KHR_device_address_commands>,
-- 'BindVertexBuffer3InfoKHR', 'Vulkan.Core10.Handles.CommandBuffer'
cmdBindVertexBuffers3KHR :: forall io
                          . (MonadIO io)
                         => -- | @commandBuffer@ is the command buffer into which the command is
                            -- recorded.
                            CommandBuffer
                         -> -- | @firstBinding@ is the index of the first vertex input binding whose
                            -- state is updated by the command.
                            ("firstBinding" ::: Word32)
                         -> -- No documentation found for Nested "vkCmdBindVertexBuffers3KHR" "pBindingInfos"
                            ("bindingInfos" ::: Vector BindVertexBuffer3InfoKHR)
                         -> io ()
cmdBindVertexBuffers3KHR commandBuffer
                           firstBinding
                           bindingInfos = liftIO . evalContT $ do
  let vkCmdBindVertexBuffers3KHRPtr = pVkCmdBindVertexBuffers3KHR (case commandBuffer of CommandBuffer{deviceCmds} -> deviceCmds)
  lift $ unless (vkCmdBindVertexBuffers3KHRPtr /= nullFunPtr) $
    throwIO $ IOError Nothing InvalidArgument "" "The function pointer for vkCmdBindVertexBuffers3KHR is null" Nothing Nothing
  let vkCmdBindVertexBuffers3KHR' = mkVkCmdBindVertexBuffers3KHR vkCmdBindVertexBuffers3KHRPtr
  pPBindingInfos <- ContT $ allocaBytes @BindVertexBuffer3InfoKHR ((Data.Vector.length (bindingInfos)) * 56)
  lift $ Data.Vector.imapM_ (\i e -> poke (pPBindingInfos `plusPtr` (56 * (i)) :: Ptr BindVertexBuffer3InfoKHR) (e)) (bindingInfos)
  lift $ traceAroundEvent "vkCmdBindVertexBuffers3KHR" (vkCmdBindVertexBuffers3KHR'
                                                          (commandBufferHandle (commandBuffer))
                                                          (firstBinding)
                                                          ((fromIntegral (Data.Vector.length $ (bindingInfos)) :: Word32))
                                                          (pPBindingInfos))
  pure $ ()


