-- 'Vulkan.Core10.Handles.CommandBuffer', 'DispatchIndirect2InfoKHR'
cmdDispatchIndirect2KHR :: forall io
                         . (MonadIO io)
                        => -- | @commandBuffer@ is the command buffer into which the command is
                           -- recorded.
                           CommandBuffer
                        -> -- | @pInfo@ is a pointer to a 'DispatchIndirect2InfoKHR' structure defining
                           -- parameters of this command.
                           DispatchIndirect2InfoKHR
                        -> io ()
cmdDispatchIndirect2KHR commandBuffer info = liftIO . evalContT $ do
  let vkCmdDispatchIndirect2KHRPtr = pVkCmdDispatchIndirect2KHR (case commandBuffer of CommandBuffer{deviceCmds} -> deviceCmds)
  lift $ unless (vkCmdDispatchIndirect2KHRPtr /= nullFunPtr) $
    throwIO $ IOError Nothing InvalidArgument "" "The function pointer for vkCmdDispatchIndirect2KHR is null" Nothing Nothing
  let vkCmdDispatchIndirect2KHR' = mkVkCmdDispatchIndirect2KHR vkCmdDispatchIndirect2KHRPtr
  pInfo <- ContT $ withCStruct (info)
  lift $ traceAroundEvent "vkCmdDispatchIndirect2KHR" (vkCmdDispatchIndirect2KHR'
                                                         (commandBufferHandle (commandBuffer))
                                                         pInfo)
  pure $ ()


foreign import ccall
#if !defined(SAFE_FOREIGN_CALLS)
  unsafe
#endif
  "dynamic" mkVkCreateAccelerationStructure2KHR
  :: FunPtr (Ptr Device_T -> Ptr (SomeStruct AccelerationStructureCreateInfo2KHR) -> Ptr AllocationCallbacks -> Ptr AccelerationStructureKHR -> IO Result) -> Ptr Device_T -> Ptr (SomeStruct AccelerationStructureCreateInfo2KHR) -> Ptr AllocationCallbacks -> Ptr AccelerationStructureKHR -> IO Result

-- | vkCreateAccelerationStructure2KHR - Create a new acceleration structure
-- object using a device address
--
-- = Description
--
-- Similar to other objects in Vulkan, the acceleration structure creation
-- merely creates an object with a specific “shape”. The type and quantity
-- of geometry that can be built into an acceleration structure is
-- determined by the parameters of 'AccelerationStructureCreateInfo2KHR'.
--
-- The acceleration structure data is stored in the object referred to by
-- 'AccelerationStructureCreateInfo2KHR'::@addressRange.address@.
--
-- Once the 'Vulkan.Extensions.Handles.AccelerationStructureKHR' object has
-- been created, it /must/ be populated by acceleration structure build or
-- acceleration structure copy commands such as
-- 'Vulkan.Extensions.VK_KHR_acceleration_structure.cmdBuildAccelerationStructuresKHR'
-- and
-- 'Vulkan.Extensions.VK_KHR_acceleration_structure.cmdCopyAccelerationStructureKHR'.
-- Acceleration structures created with this command /must/ not be used by
-- host commands.
--
-- The expected usage for a trace capture\/replay tool is that it will
-- serialize and later deserialize the acceleration structure data using
-- acceleration structure copy commands. During capture the tool will use
-- 'Vulkan.Extensions.VK_KHR_acceleration_structure.cmdCopyAccelerationStructureToMemoryKHR'
-- with a @mode@ of
-- 'Vulkan.Extensions.VK_KHR_acceleration_structure.COPY_ACCELERATION_STRUCTURE_MODE_SERIALIZE_KHR',
-- and
-- 'Vulkan.Extensions.VK_KHR_acceleration_structure.cmdCopyMemoryToAccelerationStructureKHR'
-- with a @mode@ of
-- 'Vulkan.Extensions.VK_KHR_acceleration_structure.COPY_ACCELERATION_STRUCTURE_MODE_DESERIALIZE_KHR'
-- during replay.
--
-- == Valid Usage
--
-- -   #VUID-vkCreateAccelerationStructure2KHR-accelerationStructure-03611#
--     The
--     <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#features-accelerationStructure ::accelerationStructure>
--     feature /must/ be enabled
--
-- -   #VUID-vkCreateAccelerationStructure2KHR-deviceAddressCommands-13086#
--     The
--     <https://registry.khronos.org/vulkan/specs/latest/html/vkspec.html#features-deviceAddressCommands ::deviceAddressCommands>
--     feature /must/ be enabled
--
-- == Valid Usage (Implicit)
--
-- -   #VUID-vkCreateAccelerationStructure2KHR-device-parameter# @device@
--     /must/ be a valid 'Vulkan.Core10.Handles.Device' handle
--
-- -   #VUID-vkCreateAccelerationStructure2KHR-pCreateInfo-parameter#
--     @pCreateInfo@ /must/ be a valid pointer to a valid
--     'AccelerationStructureCreateInfo2KHR' structure
--
-- -   #VUID-vkCreateAccelerationStructure2KHR-pAllocator-parameter# If
--     @pAllocator@ is not @NULL@, @pAllocator@ /must/ be a valid pointer
--     to a valid 'Vulkan.Core10.AllocationCallbacks.AllocationCallbacks'
--     structure
--
-- -   #VUID-vkCreateAccelerationStructure2KHR-pAccelerationStructure-parameter#
--     @pAccelerationStructure@ /must/ be a valid pointer to a
--     'Vulkan.Extensions.Handles.AccelerationStructureKHR' handle
--
-- -   #VUID-vkCreateAccelerationStructure2KHR-device-queuecount# The
--     device /must/ have been created with at least @1@ queue
--
-- == Return Codes
--
-- [<https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#fundamentals-successcodes Success>]
--
--     -   'Vulkan.Core10.Enums.Result.SUCCESS'
--
-- [<https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#fundamentals-errorcodes Failure>]
--
--     -   'Vulkan.Extensions.VK_KHR_buffer_device_address.ERROR_INVALID_OPAQUE_CAPTURE_ADDRESS_KHR'
--
--     -   'Vulkan.Core10.Enums.Result.ERROR_OUT_OF_HOST_MEMORY'
--
--     -   'Vulkan.Core10.Enums.Result.ERROR_UNKNOWN'
--
--     -   'Vulkan.Core10.Enums.Result.ERROR_VALIDATION_FAILED'
--
-- = See Also
--
-- <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#VK_KHR_acceleration_structure VK_KHR_acceleration_structure>,
-- <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#VK_KHR_device_address_commands VK_KHR_device_address_commands>,
-- 'AccelerationStructureCreateInfo2KHR',
-- 'Vulkan.Extensions.Handles.AccelerationStructureKHR',
-- 'Vulkan.Core10.AllocationCallbacks.AllocationCallbacks',
-- 'Vulkan.Core10.Handles.Device'
createAccelerationStructure2KHR :: forall a io
                                 . ( Extendss AccelerationStructureCreateInfo2KHR a
                                   , PokeChain a
                                   , MonadIO io )
                                => -- | @device@ is the logical device that creates the acceleration structure
                                   -- object.
                                   Device
                                -> -- | @pCreateInfo@ is a pointer to a 'AccelerationStructureCreateInfo2KHR'
                                   -- structure containing parameters affecting creation of the acceleration
                                   -- structure.
                                   (AccelerationStructureCreateInfo2KHR a)
                                -> -- | @pAllocator@ controls host memory allocation as described in the
                                   -- <https://registry.khronos.org/vulkan/specs/latest/html/vkspec.html#memory-allocation Memory Allocation>
                                   -- chapter.
                                   ("allocator" ::: Maybe AllocationCallbacks)
                                -> io (AccelerationStructureKHR)
createAccelerationStructure2KHR device
                                  createInfo
                                  allocator = liftIO . evalContT $ do
  let vkCreateAccelerationStructure2KHRPtr = pVkCreateAccelerationStructure2KHR (case device of Device{deviceCmds} -> deviceCmds)
  lift $ unless (vkCreateAccelerationStructure2KHRPtr /= nullFunPtr) $
    throwIO $ IOError Nothing InvalidArgument "" "The function pointer for vkCreateAccelerationStructure2KHR is null" Nothing Nothing
  let vkCreateAccelerationStructure2KHR' = mkVkCreateAccelerationStructure2KHR vkCreateAccelerationStructure2KHRPtr
  pCreateInfo <- ContT $ withCStruct (createInfo)
  pAllocator <- case (allocator) of
    Nothing -> pure nullPtr
    Just j -> ContT $ withCStruct (j)
  pPAccelerationStructure <- ContT $ bracket (callocBytes @AccelerationStructureKHR 8) free
  r <- lift $ traceAroundEvent "vkCreateAccelerationStructure2KHR" (vkCreateAccelerationStructure2KHR'
                                                                      (deviceHandle (device))
                                                                      (forgetExtensions pCreateInfo)
                                                                      pAllocator
                                                                      (pPAccelerationStructure))
  lift $ when (r < SUCCESS) (throwIO (VulkanException r))
  pAccelerationStructure <- lift $ peek @AccelerationStructureKHR pPAccelerationStructure
  pure $ (pAccelerationStructure)


-- | VkStridedDeviceAddressRangeKHR - Structure specifying a device address
-- range with a stride
--
-- == Valid Usage
--
-- -   #VUID-VkStridedDeviceAddressRangeKHR-size-11411# If @size@ is not 0,
--     @address@ /must/ not be 0
--
-- -   #VUID-VkStridedDeviceAddressRangeKHR-address-11365# The sum of
--     @address@ and @size@ /must/ be less than or equal to the sum of an
--     address retrieved from a 'Vulkan.Core10.Handles.Buffer' and the
--     value of 'Vulkan.Core10.Buffer.BufferCreateInfo'::@size@ used to
--     create that 'Vulkan.Core10.Handles.Buffer'
--
-- -   #VUID-VkStridedDeviceAddressRangeKHR-stride-10957# @stride@ /must/
--     be less than or equal to @size@
--
-- == Valid Usage (Implicit)
--
-- -   #VUID-VkStridedDeviceAddressRangeKHR-address-parameter# If @address@
--     is not @0@, @address@ /must/ be a valid
--     'Vulkan.Core10.FundamentalTypes.DeviceAddress' value
--
-- = See Also
--
-- <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#VK_KHR_copy_memory_indirect VK_KHR_copy_memory_indirect>,
-- <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#VK_KHR_device_address_commands VK_KHR_device_address_commands>,
-- 'BindVertexBuffer3InfoKHR',
-- 'Vulkan.Extensions.VK_KHR_copy_memory_indirect.CopyMemoryIndirectInfoKHR',
-- 'Vulkan.Extensions.VK_KHR_copy_memory_indirect.CopyMemoryToImageIndirectInfoKHR',
-- 'Vulkan.Core10.FundamentalTypes.DeviceAddress',
-- 'Vulkan.Core10.FundamentalTypes.DeviceSize', 'DrawIndirect2InfoKHR',
-- 'DrawIndirectCount2InfoKHR', 'cmdCopyQueryPoolResultsToMemoryKHR'
data StridedDeviceAddressRangeKHR = StridedDeviceAddressRangeKHR
  { -- | @address@ is a 'Vulkan.Core10.FundamentalTypes.DeviceAddress' specifying
    -- the start of the range.
    address :: DeviceAddress
  , -- | @size@ is a 'Vulkan.Core10.FundamentalTypes.DeviceSize' specifying the
    -- size of the range.
    size :: DeviceSize
  , -- | @stride@ is a 'Vulkan.Core10.FundamentalTypes.DeviceSize' specifying the
    -- stride of elements over the range.
    stride :: DeviceSize
  }
  deriving (Typeable, Eq)
#if defined(GENERIC_INSTANCES)
deriving instance Generic (StridedDeviceAddressRangeKHR)
#endif
deriving instance Show StridedDeviceAddressRangeKHR

instance ToCStruct StridedDeviceAddressRangeKHR where
  withCStruct x f = allocaBytes 24 $ \p -> pokeCStruct p x (f p)
  pokeCStruct p StridedDeviceAddressRangeKHR{..} f = do
    poke ((p `plusPtr` 0 :: Ptr DeviceAddress)) (address)
    poke ((p `plusPtr` 8 :: Ptr DeviceSize)) (size)
    poke ((p `plusPtr` 16 :: Ptr DeviceSize)) (stride)
    f
  cStructSize = 24
  cStructAlignment = 8
  pokeZeroCStruct p f = do
    poke ((p `plusPtr` 8 :: Ptr DeviceSize)) (zero)
    poke ((p `plusPtr` 16 :: Ptr DeviceSize)) (zero)
    f

instance FromCStruct StridedDeviceAddressRangeKHR where
  peekCStruct p = do
    address <- peek @DeviceAddress ((p `plusPtr` 0 :: Ptr DeviceAddress))
    size <- peek @DeviceSize ((p `plusPtr` 8 :: Ptr DeviceSize))
    stride <- peek @DeviceSize ((p `plusPtr` 16 :: Ptr DeviceSize))
    pure $ StridedDeviceAddressRangeKHR
             address size stride

instance Storable StridedDeviceAddressRangeKHR where
  sizeOf ~_ = 24
  alignment ~_ = 8
  peek = peekCStruct
  poke ptr poked = pokeCStruct ptr poked (pure ())

instance Zero StridedDeviceAddressRangeKHR where
  zero = StridedDeviceAddressRangeKHR
           zero
           zero
           zero


