-- -   #VUID-VkMemoryRangeBarrierKHR-addressRange-13098# If the buffer from
--     which the range specified by @addressRange@ was created with
--     'Vulkan.Core10.Enums.BufferCreateFlagBits.BUFFER_CREATE_PROTECTED_BIT',
--     and
--     <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#limits-protectedNoFault protectedNoFault>
--     is not supported, @addressFlags@ /must/ include
