type AddressCommandFlagsKHR = AddressCommandFlagBitsKHR

-- | VkAddressCommandFlagBitsKHR - Bitmask specifying address copy parameters
--
-- = Description
--
-- -   'ADDRESS_COMMAND_PROTECTED_BIT_KHR' specifies that an address range
--     is allocated from protected memory.
--
-- -   'ADDRESS_COMMAND_FULLY_BOUND_BIT_KHR' specifies that an address
--     range will be fully bound to physical memory when accessed.
--
-- -   'ADDRESS_COMMAND_STORAGE_BUFFER_USAGE_BIT_KHR' specifies that all
--     buffers containing any part of an address range were created with
--     the
--     'Vulkan.Core10.Enums.BufferUsageFlagBits.BUFFER_USAGE_STORAGE_BUFFER_BIT'
--     usage.
--
-- -   'ADDRESS_COMMAND_UNKNOWN_STORAGE_BUFFER_USAGE_BIT_KHR' specifies
--     that whether buffers containing an any part of an address range were
--     created with
--     'Vulkan.Core10.Enums.BufferUsageFlagBits.BUFFER_USAGE_STORAGE_BUFFER_BIT'
--     usage or not is unknown.
--
-- -   'ADDRESS_COMMAND_TRANSFORM_FEEDBACK_BUFFER_USAGE_BIT_KHR' specifies
--     that all buffers containing any part of an address range are
--     allocated with the
--     'Vulkan.Core10.Enums.BufferUsageFlagBits.BUFFER_USAGE_TRANSFORM_FEEDBACK_BUFFER_BIT_EXT'
--     usage.
--
-- -   'ADDRESS_COMMAND_UNKNOWN_TRANSFORM_FEEDBACK_BUFFER_USAGE_BIT_KHR'
--     specifies that whether buffers containing an any part of an address
--     range were created with
--     'Vulkan.Core10.Enums.BufferUsageFlagBits.BUFFER_USAGE_TRANSFORM_FEEDBACK_BUFFER_BIT_EXT'
--     usage or not is unknown.
--
-- If neither 'ADDRESS_COMMAND_STORAGE_BUFFER_USAGE_BIT_KHR' nor
-- 'ADDRESS_COMMAND_UNKNOWN_STORAGE_BUFFER_USAGE_BIT_KHR' are specified,
-- the address range /must/ not be aliased with any buffer allocated with
-- the
-- 'Vulkan.Core10.Enums.BufferUsageFlagBits.BUFFER_USAGE_STORAGE_BUFFER_BIT'.
-- If neither 'ADDRESS_COMMAND_TRANSFORM_FEEDBACK_BUFFER_USAGE_BIT_KHR' nor
-- 'ADDRESS_COMMAND_UNKNOWN_TRANSFORM_FEEDBACK_BUFFER_USAGE_BIT_KHR' are
-- specified, the address range /must/ not be aliased with any buffer
-- allocated with the
-- 'Vulkan.Core10.Enums.BufferUsageFlagBits.BUFFER_USAGE_TRANSFORM_FEEDBACK_BUFFER_BIT_EXT'.
--
-- Buffers can return overlapping address ranges if they are bound to
-- overlapping ranges of a 'Vulkan.Core10.Handles.DeviceMemory' object.
-- Applications should ensure that if they do this kind of aliasing, that
-- they consistently either include or do not include
-- 'Vulkan.Core10.Enums.BufferUsageFlagBits.BUFFER_USAGE_STORAGE_BUFFER_BIT'
-- and
-- 'Vulkan.Core10.Enums.BufferUsageFlagBits.BUFFER_USAGE_TRANSFORM_FEEDBACK_BUFFER_BIT_EXT'
-- on aliased buffers when considering these flags.
--
-- = See Also
--
-- <https://www.khronos.org/registry/vulkan/specs/1.2-extensions/html/vkspec.html#VK_KHR_device_address_commands VK_KHR_device_address_commands>,
-- 'AddressCommandFlagsKHR'
